create or replace function pg_temp.seed_uuid(label text)
returns uuid
language sql
immutable
as $$
    select (
        substr(md5(label), 1, 8) || '-' ||
        substr(md5(label), 9, 4) || '-' ||
        substr(md5(label), 13, 4) || '-' ||
        substr(md5(label), 17, 4) || '-' ||
        substr(md5(label), 21, 12)
    )::uuid;
$$;

on conflict (code) do update set name = excluded.name;

on conflict (code) do update set name_vi = excluded.name_vi, name_en = excluded.name_en;

on conflict (code) do update set name = excluded.name;

select f.id, seed.code, seed.name, seed.degree_level, seed.curriculum_year, seed.total_required_credits
from (values
        ('VIB', 'BBA', 'Bachelor of Business Administration', 'bachelor', 2026, 120),
        ('CECS', 'BS-CS', 'Bachelor of Science in Computer Science', 'bachelor', 2026, 120),
        ('CHS', 'BHS', 'Bachelor of Health Sciences', 'bachelor', 2026, 120),
        ('CASE', 'BA-LA', 'Bachelor of Arts in Liberal Arts', 'bachelor', 2026, 120)
) as seed(faculty_code, code, name, degree_level, curriculum_year, total_required_credits)
join faculties f on f.code = seed.faculty_code
on conflict (code, curriculum_year) do update set
    faculty_id = excluded.faculty_id,
    name = excluded.name,
    degree_level = excluded.degree_level,
    total_required_credits = excluded.total_required_credits;

on conflict (code) do update set
    name = excluded.name,
    start_date = excluded.start_date,
    end_date = excluded.end_date,
    academic_year = excluded.academic_year,
    term_order = excluded.term_order;

select seed.id, i.id, seed.course_code, seed.course_title, seed.credits, seed.semester, seed.academic_year, seed.instructor, true, seed.code, seed.name, seed.course_level, seed.department_code, seed.is_general_education, seed.description
from (values
