join courses c on c.code = seed.course_code and c.semester = 'Summer 2026' and c.academic_year = '2026'
join academic_terms t on t.code = '2026-SUMMER'
on conflict (course_id, term_id, section_code) do update set
    instructor_name = excluded.instructor_name,
    capacity = excluded.capacity,
    status = excluded.status;

create temporary table seed_students (
    seq integer primary key,
    user_id uuid not null,
    profile_id uuid not null,
    summary_id uuid not null,
    email text not null,
    password_hash text not null,
    student_code text not null,
    full_name text not null,
    preferred_name text not null,
    phone text,
    avatar_url text,
    institute_code text not null,
    faculty_code text not null,
    program_code text not null,
    program_name text not null,
    major text not null,
    cohort_year integer not null,
    current_year integer not null,
    preferred_language text not null,
    advisor_name text not null,
    advisor_email text not null,
    current_course_codes text[] not null,
    current_course_count integer not null,
    current_credits integer not null,
    accumulated_credits integer not null,
    gpa numeric(3,2) not null,
    academic_status text not null
) on commit preserve rows;


create temporary table seed_staff (
    user_id uuid not null,
    email text not null,
    password_hash text not null,
    full_name text not null,
    preferred_name text not null,
    role_codes text[] not null
) on commit preserve rows;


select user_id, email, password_hash, full_name, preferred_name, phone, avatar_url, 'active'
from seed_students
on conflict (email) do update set
    password_hash = excluded.password_hash,
    full_name = excluded.full_name,
    preferred_name = excluded.preferred_name,
    phone = excluded.phone,
    avatar_url = excluded.avatar_url,
    status = 'active',
    updated_at = now();

select user_id, email, password_hash, full_name, preferred_name, 'active'
from seed_staff
on conflict (email) do update set
    password_hash = excluded.password_hash,
    full_name = excluded.full_name,
    preferred_name = excluded.preferred_name,
    status = 'active',
    updated_at = now();

select u.id, r.id
from seed_students s
join users u on u.email = s.email
join roles r on r.code = 'student'
on conflict (user_id, role_id) do nothing;

select u.id, r.id
from seed_staff s
join users u on u.email = s.email
join lateral unnest(s.role_codes) as role_code(code) on true
join roles r on r.code = role_code.code
on conflict (user_id, role_id) do nothing;

select s.profile_id, u.id, s.student_code, i.id, s.program_name, s.major, s.cohort_year, s.current_year, 'active', s.preferred_language, s.advisor_name, s.advisor_email, true, s.student_code, s.full_name, f.id, p.id, s.cohort_year, s.current_year, 'active'
from seed_students s
join users u on u.email = s.email
join institutes i on i.code = s.institute_code
join faculties f on f.code = s.faculty_code
join programs p on p.code = s.program_code and p.curriculum_year = 2026
on conflict (user_id) do update set
    student_id = excluded.student_id,
    institute_id = excluded.institute_id,
    program = excluded.program,
    major = excluded.major,
    cohort = excluded.cohort,
    academic_year = excluded.academic_year,
    student_status = 'active',
    preferred_language = excluded.preferred_language,
    advisor_name = excluded.advisor_name,
    advisor_email = excluded.advisor_email,
    ai_personalization_enabled = true,
    student_code = excluded.student_code,
    full_name = excluded.full_name,
    faculty_id = excluded.faculty_id,
    program_id = excluded.program_id,
    cohort_year = excluded.cohort_year,
    current_year = excluded.current_year,
    status = 'active',
    updated_at = now();

create temporary table seed_completed_enrollments (
    student_code text not null,
    course_code text not null,
    term_code text not null,
    status text not null,
    attempt_no integer not null,
    is_improvement boolean not null,
    grade_10 numeric(4,2),
    grade_4 numeric(3,2),
    letter_grade text,
    passed boolean not null,
    earned_credits integer not null,
    is_gpa_counted boolean not null
) on commit preserve rows;


select
    pg_temp.seed_uuid('realistic-sce-completed:' || e.student_code || ':' || e.course_code || ':' || e.term_code || ':' || e.attempt_no),
    sp.id, c.id, t.id, null::uuid, e.status, e.attempt_no, e.is_improvement, null::uuid, e.grade_10, e.grade_4, e.letter_grade, e.passed, e.earned_credits, e.is_gpa_counted, (t.end_date::text || ' 17:00:00+07')::timestamptz
from seed_completed_enrollments e
join student_profiles sp on sp.student_id = e.student_code
join courses c on c.code = e.course_code and c.semester = 'Summer 2026' and c.academic_year = '2026'
join academic_terms t on t.code = e.term_code
on conflict (student_id, course_id, term_id, attempt_no) do update set
    status = excluded.status,
    grade_10 = excluded.grade_10,
    grade_4 = excluded.grade_4,
    letter_grade = excluded.letter_grade,
    passed = excluded.passed,
    earned_credits = excluded.earned_credits,
    is_gpa_counted = excluded.is_gpa_counted,
    completed_at = excluded.completed_at;

select
    pg_temp.seed_uuid('realistic-sce-current:' || s.student_code || ':' || current_course.course_code || ':2026-SUMMER'),
    sp.id, c.id, t.id, cs.id, 'enrolled', 1, false, null::uuid, null::numeric, null::numeric, null, false, 0, false, null::timestamptz
from seed_students s
join student_profiles sp on sp.student_id = s.student_code
join lateral unnest(s.current_course_codes) as current_course(course_code) on true
join courses c on c.code = current_course.course_code and c.semester = 'Summer 2026' and c.academic_year = '2026'
join academic_terms t on t.code = '2026-SUMMER'
join course_sections cs on cs.course_id = c.id and cs.term_id = t.id and cs.section_code = c.code || '-A'
on conflict (student_id, course_id, term_id, attempt_no) do update set
    section_id = excluded.section_id,
    status = excluded.status,
    grade_10 = null,
    grade_4 = null,
    letter_grade = null,
    passed = false,
    earned_credits = 0,
    is_gpa_counted = false,
    completed_at = null;

