        ('SOC310-A', 1, '08:30', 90, 'lecture', 'CASE Studio', 'CST101'),
        ('SOC310-A', 3, '08:30', 90, 'lecture', 'CASE Studio', 'CST101'),
        ('RES300-A', 2, '08:30', 90, 'lecture', 'CASE Studio', 'CST101'),
        ('RES300-A', 4, '08:30', 90, 'lecture', 'CASE Studio', 'CST101'),
        ('EDU320-A', 1, '10:15', 90, 'lecture', 'CASE Studio', 'CST101'),
        ('EDU320-A', 3, '10:15', 90, 'lecture', 'CASE Studio', 'CST101'),
        ('ART330-A', 2, '10:15', 90, 'lecture', 'CASE Studio', 'CST101'),
        ('ART330-A', 4, '10:15', 90, 'lecture', 'CASE Studio', 'CST101'),
        ('STA210-A', 1, '13:30', 90, 'lecture', 'CASE Studio', 'CST101'),
        ('STA210-A', 3, '13:30', 90, 'lecture', 'CASE Studio', 'CST101'),
        ('CAP410-A', 2, '13:30', 90, 'lecture', 'CASE Studio', 'CST101'),
        ('CAP410-A', 4, '13:30', 90, 'lecture', 'CASE Studio', 'CST101'),
        ('CAP410-A', 5, '13:30', 120, 'lab', 'CASE Studio', 'CST101')
), days as (
    select g::date as d
    from generate_series(date '2026-06-01', date '2026-07-31', interval '1 day') g
)
select
    pg_temp.seed_uuid('realistic-class-meeting:' || cs.section_code || ':' || days.d::text || ':' || slot.start_time::text || ':' || slot.meeting_type || ':' || slot.dur_min::text),
    cs.id,
    c.code || ' ' || initcap(replace(slot.meeting_type, '_', ' ')) || ' - ' || to_char(days.d, 'Dy DD Mon'),
    slot.meeting_type,
    (days.d + slot.start_time::time) at time zone 'Asia/Ho_Chi_Minh',
    (days.d + slot.start_time::time + make_interval(mins => slot.dur_min)) at time zone 'Asia/Ho_Chi_Minh',
    r.id,
    'Summer 2026 recurring class meeting.'
from slot
join days on extract(dow from days.d) = slot.dow
join course_sections cs on cs.section_code = slot.section_code
join academic_terms t on t.id = cs.term_id and t.code = '2026-SUMMER'
join courses c on c.id = cs.course_id
left join rooms r on r.building = slot.building and r.room_name = slot.room_name
on conflict (section_id, title, start_at) do update set
    meeting_type = excluded.meeting_type,
    end_at = excluded.end_at,
    room_id = excluded.room_id,
    note = excluded.note;

with current_enrollments as (
    select
        sce.id as enrollment_id,
        sp.id as student_profile_id,
        sp.student_id as student_code,
        c.id as course_id,
        c.code as course_code,
        c.name as course_name,
        c.credits,
        c.department_code,
        cs.id as section_id,
        cs.section_code,
        cs.instructor_name,
        row_number() over (partition by sp.id order by c.code) as course_rank
    from student_course_enrollments sce
    join student_profiles sp on sp.id = sce.student_id
    join courses c on c.id = sce.course_id
    join academic_terms t on t.id = sce.term_id and t.code = '2026-SUMMER'
    left join course_sections cs on cs.id = sce.section_id
    where sce.status in ('planned', 'enrolled', 'retaking', 'improvement')
      and sp.student_id in (select student_code from seed_students)
), rank_slots(course_rank, slot_no, dow, start_time, dur_min) as (
    values
        (1, 1, 1, '08:30'::time, 90),
        (1, 2, 3, '08:30'::time, 90),
        (2, 1, 2, '08:30'::time, 90),
        (2, 2, 4, '08:30'::time, 90),
        (3, 1, 5, '08:30'::time, 90),
        (3, 2, 1, '10:30'::time, 90),
        (4, 1, 2, '10:30'::time, 90),
        (4, 2, 4, '10:30'::time, 90),
        (5, 1, 3, '10:30'::time, 90),
        (5, 2, 5, '10:30'::time, 90),
        (6, 1, 1, '13:30'::time, 90),
        (6, 2, 3, '13:30'::time, 90),
        (7, 1, 2, '13:30'::time, 90),
        (7, 2, 4, '13:30'::time, 90)
), days as (
    select g::date as d
    from generate_series(date '2026-06-01', date '2026-07-31', interval '1 day') g
), scheduled as (
    select
        ce.*,
        rs.slot_no,
        rs.start_time,
        rs.dur_min,
        days.d,
        case
            when ce.course_code like 'LAB%' or ce.course_code like 'PE%' then 'lab'
            when rs.slot_no = 2 and ce.credits > 0 then 'tutorial'
            else 'lecture'
        end as meeting_type,
        case
            when ce.department_code in ('BUS', 'ECON', 'LAW', 'INT', 'CAP') then 'Business School'
            when ce.department_code in ('CSC', 'MAT', 'PHY', 'ECE') then 'Academic Building A'
            when ce.department_code in ('HSC', 'BIO', 'CHEM', 'MED', 'NUR', 'CLN') then 'Health Sciences Lab'
            when ce.course_code like 'PE%' then 'Sports Complex'
            else 'CASE Studio'
        end as building,
        case
            when ce.department_code in ('BUS', 'ECON', 'LAW', 'INT', 'CAP') then 'VIB301'
            when ce.department_code in ('CSC', 'MAT', 'PHY', 'ECE') then 'A101'
            when ce.department_code in ('HSC', 'BIO', 'CHEM', 'MED', 'NUR', 'CLN') then 'HSL201'
            when ce.course_code like 'PE%' then 'Gym 1'
            else 'CST101'
        end as room
    from current_enrollments ce
    join rank_slots rs on rs.course_rank = ce.course_rank
    join days on extract(dow from days.d) = rs.dow
    where ce.credits > 0 or rs.slot_no = 1
)
    id,
    student_id,
    enrollment_id,
    course_id,
    section_id,
    title,
    meeting_type,
    start_at,
    end_at,
    location,
    building,
    room,
    instructor,
    note
)
select
    pg_temp.seed_uuid('realistic-student-schedule:' || student_code || ':' || enrollment_id::text || ':' || d::text || ':' || start_time::text || ':' || meeting_type),
    student_profile_id,
    enrollment_id,
    course_id,
    section_id,
    course_code || ' ' || initcap(meeting_type) || ' - ' || to_char(d, 'Dy DD Mon'),
    meeting_type,
    (d + start_time) at time zone 'Asia/Ho_Chi_Minh',
    (d + start_time + make_interval(mins => dur_min)) at time zone 'Asia/Ho_Chi_Minh',
    'VinUni Campus',
    building,
    room,
    instructor_name,
    'Generated student calendar event for Summer 2026.'
from scheduled
on conflict (student_id, enrollment_id, start_at, title) do update set
    course_id = excluded.course_id,
    section_id = excluded.section_id,
    meeting_type = excluded.meeting_type,
    end_at = excluded.end_at,
    location = excluded.location,
    building = excluded.building,
    room = excluded.room,
    instructor = excluded.instructor,
    note = excluded.note;

select
    pg_temp.seed_uuid('realistic-deadline:' || s.student_code || ':' || cc.course_code || ':' || cc.ordinality),
    sp.id, c.id, c.code || ' Assignment ' || cc.ordinality, 'assignment',
    (date '2026-07-03' + ((s.seq + cc.ordinality::integer * 7) % 24)::integer)::date + time '23:59' at time zone 'Asia/Ho_Chi_Minh',
    'Summer 2026 course LMS', null
from seed_students s
join student_profiles sp on sp.student_id = s.student_code
join lateral unnest(s.current_course_codes[1:2]) with ordinality as cc(course_code, ordinality) on true
join courses c on c.code = cc.course_code and c.semester = 'Summer 2026' and c.academic_year = '2026'
on conflict (id) do update set
    student_profile_id = excluded.student_profile_id,
    course_id = excluded.course_id,
    title = excluded.title,
    kind = excluded.kind,
    due_at = excluded.due_at,
    source_title = excluded.source_title,
    source_url = excluded.source_url;

with qdrant_event_seed(slug, notification_type, title_en, title_vi, message_en, message_vi, priority, target_scope, deadline, event_date, end_date) as (
    values
        ('qdrant-fall26-instruction-begins', 'academic', 'Fall 2026 instruction begins', 'Hoc ky Thu 2026 bat dau giang day', 'Fall 2026 instruction begins on 21 Sep 2026 according to the VinUni Academic Calendar.', 'Hoc ky Thu 2026 bat dau giang day ngay 21/09/2026 theo lich hoc vu VinUni.', 'medium', 'all', null, '2026-09-21 08:00:00+07', null),
        ('qdrant-add-transfer-deadline', 'deadline', 'Add/Transfer Credit/Independent Study deadline', 'Han add/transfer credit/independent study', 'Deadline from the VinUni Academic Calendar: 1 Oct 2026.', 'Han theo lich hoc vu VinUni: 01/10/2026.', 'high', 'all', '2026-10-01 23:59:00+07', null, null),
        ('qdrant-course-drop-deadline', 'deadline', 'Course drop deadline', 'Han rut hoc phan', 'Course drop deadline from the VinUni Academic Calendar: 9 Oct 2026.', 'Han rut hoc phan theo lich hoc vu VinUni: 09/10/2026.', 'high', 'all', '2026-10-09 23:59:00+07', null, null),
        ('qdrant-final-exam-release', 'academic', 'Final exam schedule release', 'Cong bo lich thi cuoi ky', 'Final exam schedule release date from the VinUni Academic Calendar: 7 Dec 2026.', 'Ngay cong bo lich thi cuoi ky theo lich hoc vu VinUni: 07/12/2026.', 'medium', 'all', null, '2026-12-07 09:00:00+07', null),
        ('qdrant-course-evaluation-fall26', 'academic', 'End-of-semester course evaluation period', 'Dot danh gia mon hoc cuoi ky', 'Fall 2026 course evaluation period runs from 21 Dec to 31 Dec 2026.', 'Dot danh gia mon hoc Thu 2026 tu 21/12 den 31/12/2026.', 'medium', 'all', null, '2026-12-21 09:00:00+07', '2026-12-31 23:59:00+07'),
        ('qdrant-spring27-registration', 'deadline', 'Spring 2027 class enrollment starts', 'Bat dau dang ky lop hoc Xuan 2027', 'Spring 2027 class enrollment starts on 24 Dec 2026 according to the VinUni Academic Calendar.', 'Dang ky lop hoc Xuan 2027 bat dau ngay 24/12/2026 theo lich hoc vu VinUni.', 'high', 'all', '2026-12-24 09:00:00+07', null, null)
), source as (
    select
        slug,
        notification_type,
        title_en,
        title_vi,
        message_en,
        message_vi,
        priority,
        target_scope,
        deadline::timestamptz as deadline,
        event_date::timestamptz as event_date,
        end_date::timestamptz as end_date,
        'VinUni Academic Calendar AY26-27'::text as source_title,
        'https://policy.vinuni.edu.vn/wp-content/uploads/2025/06/VinUni-Academic-Calendar.pdf'::text as source_url
    from qdrant_event_seed
)
select
    pg_temp.seed_uuid('realistic-event:' || slug), title_en, message_en || ' Source: ' || source_title, notification_type, 'VinUni Campus',
    coalesce(event_date, deadline, '2026-09-21 08:00:00+07'::timestamptz),
    coalesce(end_date, event_date + interval '2 hours', deadline + interval '1 hour'),
    null::uuid, target_scope, false, null::timestamptz
from source
on conflict (id) do update set
    title = excluded.title,
    description = excluded.description,
    event_type = excluded.event_type,
    location = excluded.location,
    start_time = excluded.start_time,
    end_time = excluded.end_time,
    target_scope = excluded.target_scope;

with qdrant_event_seed(slug, notification_type, title_en, title_vi, message_en, message_vi, priority, target_scope, deadline, event_date, end_date) as (
    values
        ('qdrant-fall26-instruction-begins', 'academic', 'Fall 2026 instruction begins', 'Hoc ky Thu 2026 bat dau giang day', 'Fall 2026 instruction begins on 21 Sep 2026 according to the VinUni Academic Calendar.', 'Hoc ky Thu 2026 bat dau giang day ngay 21/09/2026 theo lich hoc vu VinUni.', 'medium', 'all', null, '2026-09-21 08:00:00+07', null),
        ('qdrant-add-transfer-deadline', 'deadline', 'Add/Transfer Credit/Independent Study deadline', 'Han add/transfer credit/independent study', 'Deadline from the VinUni Academic Calendar: 1 Oct 2026.', 'Han theo lich hoc vu VinUni: 01/10/2026.', 'high', 'all', '2026-10-01 23:59:00+07', null, null),
        ('qdrant-course-drop-deadline', 'deadline', 'Course drop deadline', 'Han rut hoc phan', 'Course drop deadline from the VinUni Academic Calendar: 9 Oct 2026.', 'Han rut hoc phan theo lich hoc vu VinUni: 09/10/2026.', 'high', 'all', '2026-10-09 23:59:00+07', null, null),
        ('qdrant-final-exam-release', 'academic', 'Final exam schedule release', 'Cong bo lich thi cuoi ky', 'Final exam schedule release date from the VinUni Academic Calendar: 7 Dec 2026.', 'Ngay cong bo lich thi cuoi ky theo lich hoc vu VinUni: 07/12/2026.', 'medium', 'all', null, '2026-12-07 09:00:00+07', null),
        ('qdrant-course-evaluation-fall26', 'academic', 'End-of-semester course evaluation period', 'Dot danh gia mon hoc cuoi ky', 'Fall 2026 course evaluation period runs from 21 Dec to 31 Dec 2026.', 'Dot danh gia mon hoc Thu 2026 tu 21/12 den 31/12/2026.', 'medium', 'all', null, '2026-12-21 09:00:00+07', '2026-12-31 23:59:00+07'),
        ('qdrant-spring27-registration', 'deadline', 'Spring 2027 class enrollment starts', 'Bat dau dang ky lop hoc Xuan 2027', 'Spring 2027 class enrollment starts on 24 Dec 2026 according to the VinUni Academic Calendar.', 'Dang ky lop hoc Xuan 2027 bat dau ngay 24/12/2026 theo lich hoc vu VinUni.', 'high', 'all', '2026-12-24 09:00:00+07', null, null)
), source as (
    select
        slug,
        notification_type,
        title_en,
        title_vi,
        message_en,
        message_vi,
        priority,
        target_scope,
        deadline::timestamptz as deadline,
        event_date::timestamptz as event_date,
        end_date::timestamptz as end_date,
        'VinUni Academic Calendar AY26-27'::text as source_title,
        'https://policy.vinuni.edu.vn/wp-content/uploads/2025/06/VinUni-Academic-Calendar.pdf'::text as source_url
    from qdrant_event_seed
)
select
    pg_temp.seed_uuid('realistic-notification:' || slug), notification_type, title_en, message_en, title_vi, title_en, message_vi, message_en, priority, 'published', target_scope, null::uuid, null::uuid, null::integer, deadline, event_date, '2026-06-20 08:00:00+07'::timestamptz, coalesce(end_date, deadline, event_date, '2027-01-31 23:59:00+07'::timestamptz), source_title, source_url, (select id from users where email = 'academic.affairs@vinuni.edu.vn')
from source
on conflict (id) do update set
    type = excluded.type,
    title = excluded.title,
    message = excluded.message,
    title_vi = excluded.title_vi,
    title_en = excluded.title_en,
    message_vi = excluded.message_vi,
    message_en = excluded.message_en,
    priority = excluded.priority,
    status = excluded.status,
    target_scope = excluded.target_scope,
    deadline = excluded.deadline,
    event_date = excluded.event_date,
    start_date = excluded.start_date,
    end_date = excluded.end_date,
    source_title = excluded.source_title,
    source_url = excluded.source_url,
    created_by = excluded.created_by,
    updated_at = now();

select
    pg_temp.seed_uuid('realistic-notification-read:' || n.id::text || ':' || u.email),
    n.id, u.id, '2026-06-30 09:00:00+07'::timestamptz + make_interval(mins => s.seq), n.priority in ('high', 'urgent'), false
from seed_students s
join users u on u.email = s.email
join notifications n on n.id in (
    pg_temp.seed_uuid('realistic-notification:qdrant-add-transfer-deadline'),
    pg_temp.seed_uuid('realistic-notification:qdrant-course-drop-deadline'),
    pg_temp.seed_uuid('realistic-notification:qdrant-fall26-instruction-begins')
)
where s.seq % 3 = 0
on conflict (notification_id, user_id) do update set
    read_at = excluded.read_at,
    important = excluded.important,
    archived = excluded.archived;

select
    pg_temp.seed_uuid('realistic-conversation:' || s.student_code || ':support'),
    u.id, 'Summer schedule and support request', false, 'student_support',
    '2026-06-15 10:00:00+07'::timestamptz + make_interval(hours => s.seq),
    '2026-06-15 10:20:00+07'::timestamptz + make_interval(hours => s.seq),
    '2026-06-15 10:20:00+07'::timestamptz + make_interval(hours => s.seq)
from seed_students s
join users u on u.email = s.email
where s.seq % 2 = 0
on conflict (id) do update set
    user_id = excluded.user_id,
    title = excluded.title,
    topic = excluded.topic,
    updated_at = excluded.updated_at,
    last_message_at = excluded.last_message_at;

select pg_temp.seed_uuid('realistic-message:' || c.id::text || ':1'), c.id, 'user', 'I need help checking my summer schedule and next deadline.', null::jsonb, 'schedule_lookup', 'student_support', 0.91, false, c.created_at
from conversations c
where c.id::text in (select pg_temp.seed_uuid('realistic-conversation:' || student_code || ':support')::text from seed_students where seq % 2 = 0)
on conflict (id) do update set content = excluded.content, intent = excluded.intent, topic = excluded.topic;

select pg_temp.seed_uuid('realistic-message:' || c.id::text || ':2'), c.id, 'assistant', 'Your current timetable is available in the schedule page. I can draft a support ticket if you need staff confirmation.', null::jsonb, 'schedule_lookup', 'student_support', 0.90, false, c.created_at + interval '5 minutes'
from conversations c
where c.id::text in (select pg_temp.seed_uuid('realistic-conversation:' || student_code || ':support')::text from seed_students where seq % 2 = 0)
on conflict (id) do update set content = excluded.content, intent = excluded.intent, topic = excluded.topic;

select
    pg_temp.seed_uuid('realistic-ticket:' || s.student_code || ':summer-support'),
    sp.id, i.id,
    case s.institute_code
        when 'CECS' then 'Lab access and summer schedule confirmation'
        when 'CHS' then 'Clinical lab schedule and requirement check'
        when 'VIB' then 'Course registration and tuition support'
        else 'Writing support and course planning request'
    end,
    'Student requests staff confirmation for Summer 2026 schedule, deadlines, and next action.',
    s.institute_code,
    case s.institute_code when 'CECS' then 'lab_schedule' when 'CHS' then 'clinical_schedule' when 'VIB' then 'registration' else 'academic_support' end,
    case when s.seq % 11 = 0 then 'urgent' when s.seq % 5 = 0 then 'high' when s.seq % 3 = 0 then 'low' else 'medium' end,
    case s.seq % 6 when 0 then 'submitted' when 1 then 'open' when 2 then 'in_progress' when 3 then 'waiting_on_student' when 4 then 'resolved' else 'closed' end,
    true, false, true, null,
    pg_temp.seed_uuid('realistic-conversation:' || s.student_code || ':support'),
    'I need help checking my summer schedule and next deadline.',
    admin_u.id,
    '2026-06-05 09:00:00+07'::timestamptz + make_interval(hours => s.seq),
    '2026-06-08 09:00:00+07'::timestamptz + make_interval(hours => s.seq),
    48,
    case when s.seq % 6 in (4,5) then 'Staff confirmed the schedule/deadline path and closed the request.' else null end,
    false, false,
    '2026-06-05 09:00:00+07'::timestamptz + make_interval(hours => s.seq),
    '2026-06-06 10:00:00+07'::timestamptz + make_interval(hours => s.seq)
from seed_students s
join student_profiles sp on sp.student_id = s.student_code
join institutes i on i.code = s.institute_code
join users admin_u on admin_u.email = case s.institute_code when 'VIB' then 'vib.advising@vinuni.edu.vn' when 'CECS' then 'cecs.advising@vinuni.edu.vn' when 'CHS' then 'chs.advising@vinuni.edu.vn' else 'case.advising@vinuni.edu.vn' end
where s.seq % 2 = 0
on conflict (id) do update set
    student_profile_id = excluded.student_profile_id,
    institute_id = excluded.institute_id,
    subject = excluded.subject,
    body = excluded.body,
    department = excluded.department,
    category = excluded.category,
    priority = excluded.priority,
    status = excluded.status,
    include_chat_context = excluded.include_chat_context,
    source_conversation_id = excluded.source_conversation_id,
    origin_question = excluded.origin_question,
    assigned_admin_id = excluded.assigned_admin_id,
    submitted_at = excluded.submitted_at,
    due_at = excluded.due_at,
    sla_hours = excluded.sla_hours,
    resolution = excluded.resolution,
    archived = false,
    deleted = false,
    updated_at = excluded.updated_at;

select pg_temp.seed_uuid('realistic-ticket-message:' || t.id::text || ':student'), t.id, u.id, 'student', 'Could you confirm the schedule/deadline information in my portal?', t.created_at
from tickets t
join student_profiles sp on sp.id = t.student_profile_id
join users u on u.id = sp.user_id
where t.id::text in (select pg_temp.seed_uuid('realistic-ticket:' || student_code || ':summer-support')::text from seed_students where seq % 2 = 0)
on conflict (id) do update set body = excluded.body, created_at = excluded.created_at;

select pg_temp.seed_uuid('realistic-ticket-message:' || t.id::text || ':staff'), t.id, t.assigned_admin_id, 'admin', 'Thanks. We are checking your Summer 2026 timetable and will update the ticket.', t.created_at + interval '2 hours'
from tickets t
where t.id::text in (select pg_temp.seed_uuid('realistic-ticket:' || student_code || ':summer-support')::text from seed_students where seq % 2 = 0)
on conflict (id) do update set sender_user_id = excluded.sender_user_id, body = excluded.body, created_at = excluded.created_at;

select pg_temp.seed_uuid('realistic-ticket-status:' || t.id::text || ':submitted'), t.id, null, 'submitted', null::uuid, t.created_at
from tickets t
where t.id::text in (select pg_temp.seed_uuid('realistic-ticket:' || student_code || ':summer-support')::text from seed_students where seq % 2 = 0)
on conflict (id) do update set new_status = excluded.new_status, changed_at = excluded.changed_at;

select pg_temp.seed_uuid('realistic-ticket-status:' || t.id::text || ':' || t.status), t.id, 'submitted', t.status, t.assigned_admin_id, t.created_at + interval '2 hours'
from tickets t
where t.status <> 'submitted'
  and t.id::text in (select pg_temp.seed_uuid('realistic-ticket:' || student_code || ':summer-support')::text from seed_students where seq % 2 = 0)
on conflict (id) do update set old_status = excluded.old_status, new_status = excluded.new_status, changed_by = excluded.changed_by, changed_at = excluded.changed_at;

on conflict (slug) do update set
    name_en = excluded.name_en,
    name_vi = excluded.name_vi,
    description_en = excluded.description_en,
    description_vi = excluded.description_vi,
    color = excluded.color,
    sort_order = excluded.sort_order,
    is_active = excluded.is_active;

create temporary table seed_forum_topics (topic_id uuid not null, category_slug text not null, title text not null, content text not null, tags text[] not null, author_seq integer not null) on commit preserve rows;


select ft.topic_id, cat.id, u.id, ft.title, ft.content, ft.tags, '[]'::jsonb, ft.author_seq in (2,7), false, 20 + ft.author_seq, false, '2026-06-18 09:00:00+07'::timestamptz + make_interval(hours => ft.author_seq), '2026-06-25 09:00:00+07'::timestamptz + make_interval(hours => ft.author_seq), '2026-06-25 09:00:00+07'::timestamptz + make_interval(hours => ft.author_seq)
from seed_forum_topics ft
join forum_categories cat on cat.slug = ft.category_slug
join seed_students s on s.seq = ft.author_seq
join users u on u.email = s.email
on conflict (id) do update set
    category_id = excluded.category_id,
    author_user_id = excluded.author_user_id,
    title = excluded.title,
    content = excluded.content,
    tags = excluded.tags,
    is_pinned = excluded.is_pinned,
    is_locked = excluded.is_locked,
    view_count = excluded.view_count,
    deleted = false,
    updated_at = excluded.updated_at,
    last_activity_at = excluded.last_activity_at;

select pg_temp.seed_uuid('realistic-forum-comment:' || ft.topic_id::text || ':student'), ft.topic_id, u.id, null::uuid, 'I had the same question and found the portal schedule plus advisor note useful.', false, false, '2026-06-26 08:00:00+07'::timestamptz + make_interval(hours => ft.author_seq), '2026-06-26 08:00:00+07'::timestamptz + make_interval(hours => ft.author_seq)
from seed_forum_topics ft
join seed_students s on s.seq = ft.author_seq + 1
join users u on u.email = s.email
on conflict (id) do update set content = excluded.content, deleted = false, updated_at = excluded.updated_at;

select pg_temp.seed_uuid('realistic-forum-comment:' || ft.topic_id::text || ':official'), ft.topic_id, admin_u.id, null::uuid, 'Official note: please rely on the student portal for your personal timetable and open a ticket if there is a mismatch.', true, false, '2026-06-26 12:00:00+07'::timestamptz + make_interval(hours => ft.author_seq), '2026-06-26 12:00:00+07'::timestamptz + make_interval(hours => ft.author_seq)
from seed_forum_topics ft
join users admin_u on admin_u.email = 'academic.affairs@vinuni.edu.vn'
on conflict (id) do update set author_user_id = excluded.author_user_id, content = excluded.content, is_official = true, deleted = false, updated_at = excluded.updated_at;

update forum_topics t
set official_comment_id = c.id
from forum_comments c
where c.topic_id = t.id and c.is_official = true
  and t.id in (select topic_id from seed_forum_topics);

select pg_temp.seed_uuid('realistic-forum-vote:' || ft.topic_id::text || ':' || s.student_code), u.id, 'topic', ft.topic_id, 1, '2026-06-27 09:00:00+07'::timestamptz + make_interval(mins => s.seq)
from seed_forum_topics ft
join seed_students s on s.seq between greatest(1, ft.author_seq - 2) and least(100, ft.author_seq + 2)
join users u on u.email = s.email
on conflict (user_id, target_type, target_id) do update set value = excluded.value;

select
    pg_temp.seed_uuid('realistic-suggested-question:' || n.id::text),
    'What should I do next for ' || n.title || '?',
    'Toi can lam gi tiep theo cho thong bao nay?',
    'What should I do next for ' || n.title || '?',
    'notification', n.id, n.id, n.type, 'clarify_next_step', n.type, 'announcement', n.institute_id, n.course_id, n.cohort, 8.500, 4, true, true, true, n.start_date, n.end_date
from notifications n
where n.id::text like pg_temp.seed_uuid('realistic-notification:qdrant-fall26-instruction-begins')::text
   or n.source_title = 'VinUni Academic Calendar AY26-27'
on conflict (id) do update set
    question_text = excluded.question_text,
    question_text_vi = excluded.question_text_vi,
    question_text_en = excluded.question_text_en,
    notification_id = excluded.notification_id,
    is_active = true,
    updated_at = now();
